import{_ as s,o as i,c as a,a2 as l}from"./chunks/framework.CGYl2SZ_.js";const n=JSON.parse('{"title":"matrix","description":"matrix 页面","frontmatter":{"title":"matrix","description":"matrix 页面"},"headers":[],"relativePath":"channels/matrix.md","filePath":"channels/matrix.md"}');const t=s({name:"channels/matrix.md"},[["render",function(s,n,t,e,h,p){return i(),a("div",null,[...n[0]||(n[0]=[l('<h1 id="matrix" tabindex="-1">Matrix <a class="header-anchor" href="#matrix" aria-label="Permalink to &quot;Matrix&quot;">​</a></h1><h1 id="matrix-插件" tabindex="-1">Matrix（插件） <a class="header-anchor" href="#matrix-插件" aria-label="Permalink to &quot;Matrix（插件）&quot;">​</a></h1><p>Matrix 是一个开放的、去中心化的消息协议。OpenClaw 作为 Matrix <strong>用户</strong>连接任何 homeserver，因此您需要为机器人创建 Matrix 账户。登录后，您可以直接私信机器人或将其邀请到房间（Matrix&quot;群组&quot;）。Beeper 也是有效的客户端选项，但它需要启用 E2EE。</p><p>状态：通过插件支持（@vector-im/matrix-bot-sdk）。支持私信、房间、线程、媒体、反应、投票（发送 + 投票开始作为文本）、位置和 E2EE（带加密支持）。</p><h2 id="需要插件" tabindex="-1">需要插件 <a class="header-anchor" href="#需要插件" aria-label="Permalink to &quot;需要插件&quot;">​</a></h2><p>Matrix 作为插件发货，未与核心安装捆绑。</p><p>通过 CLI 安装（npm 注册表）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @openclaw/matrix</span></span></code></pre></div><p>本地检出（从 git 仓库运行时）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./extensions/matrix</span></span></code></pre></div><p>如果您在设置中选择 Matrix 并且检测到 git 检出，OpenClaw 会自动提供本地安装路径。</p><p>详情：<a href="/tools/plugin.html">插件</a></p><h2 id="设置" tabindex="-1">设置 <a class="header-anchor" href="#设置" aria-label="Permalink to &quot;设置&quot;">​</a></h2><ol><li><p>安装 Matrix 插件：</p><ul><li>从 npm：<code>openclaw plugins install @openclaw/matrix</code></li><li>从本地检出：<code>openclaw plugins install ./extensions/matrix</code></li></ul></li><li><p>在 homeserver 上创建 Matrix 账户：</p><ul><li>浏览托管选项 <a href="https://matrix.org/ecosystem/hosting/" target="_blank" rel="noreferrer">https://matrix.org/ecosystem/hosting/</a></li><li>或自行托管。</li></ul></li><li><p>获取机器人账户的访问令牌：</p><ul><li>使用 <code>curl</code> 在您的 home 服务器上使用 Matrix 登录 API：</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --request</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://matrix.example.org/_matrix/client/v3/login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --header</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Content-Type: application/json&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --data</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;type&quot;: &quot;m.login.password&quot;,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;identifier&quot;: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;type&quot;: &quot;m.id.user&quot;,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;user&quot;: &quot;your-user-name&quot;</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  },</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;password&quot;: &quot;your-password&quot;</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&#39;</span></span></code></pre></div><ul><li>将 <code>matrix.example.org</code> 替换为您的 homeserver URL。</li><li>或设置 <code>channels.matrix.userId</code> + <code>channels.matrix.password</code>：OpenClaw 调用相同的登录端点，将访问令牌存储在 <code>~/.openclaw/credentials/matrix/credentials.json</code> 中，并在下次启动时重用它。</li></ul></li><li><p>配置凭据：</p><ul><li>环境变量：<code>MATRIX_HOMESERVER</code>、<code>MATRIX_ACCESS_TOKEN</code>（或 <code>MATRIX_USER_ID</code> + <code>MATRIX_PASSWORD</code>）</li><li>或配置：<code>channels.matrix.*</code></li><li>如果两者都设置，配置优先。</li><li>使用访问令牌：用户 ID 通过 <code>/whoami</code> 自动获取。</li><li>设置时，<code>channels.matrix.userId</code> 应该是完整的 Matrix ID（例如 <code>@bot:example.org</code>）。</li></ul></li><li><p>重启网关（或完成设置）。</p></li><li><p>从任何 Matrix 客户端（Element、Beeper 等；参见 <a href="https://matrix.org/ecosystem/clients/" target="_blank" rel="noreferrer">https://matrix.org/ecosystem/clients/</a>）开始与机器人私信或将其邀请到房间。Beeper 需要 E2EE，因此设置 <code>channels.matrix.encryption: true</code> 并验证设备。</p></li></ol><p>最小配置（访问令牌，用户 ID 自动获取）：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    matrix</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      homeserver</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://matrix.example.org&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      accessToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;syt_***&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      dm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">policy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pairing&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>E2EE 配置（启用端到端加密）：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    matrix</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      homeserver</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://matrix.example.org&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      accessToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;syt_***&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      encryption</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      dm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">policy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pairing&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="加密-e2ee" tabindex="-1">加密（E2EE） <a class="header-anchor" href="#加密-e2ee" aria-label="Permalink to &quot;加密（E2EE）&quot;">​</a></h2><p>通过 Rust 加密 SDK <strong>支持</strong>端到端加密。</p><p>使用 <code>channels.matrix.encryption: true</code> 启用：</p><ul><li>如果加密模块加载，加密房间会自动解密。</li><li>出站媒体在发送到加密房间时加密。</li><li>首次连接时，OpenClaw 向您的其他会话请求设备验证。</li><li>在另一个 Matrix 客户端（Element 等）中验证设备以启用密钥共享。</li><li>如果无法加载加密模块，E2EE 被禁用且加密房间不会解密；OpenClaw 记录警告。</li><li>如果看到缺少加密模块错误（例如 <code>@matrix-org/matrix-sdk-crypto-nodejs-*</code>），允许 <code>@matrix-org/matrix-sdk-crypto-nodejs</code> 的构建脚本并运行 <code>pnpm rebuild @matrix-org/matrix-sdk-crypto-nodejs</code> 或使用 <code>node node_modules/@matrix-org/matrix-sdk-crypto-nodejs/download-lib.js</code> 获取二进制文件。</li></ul><p>加密状态按账户 + 访问令牌存储在 <code>~/.openclaw/matrix/accounts/&lt;account&gt;/&lt;homeserver&gt;__&lt;user&gt;/&lt;token-hash&gt;/crypto/</code>（SQLite 数据库）。同步状态与其一起存储在 <code>bot-storage.json</code> 中。如果访问令牌（设备）更改，会创建新存储，机器人必须为加密房间重新验证。</p><p><strong>设备验证：</strong> 启用 E2EE 后，机器人在启动时将向您的其他会话请求验证。打开 Element（或另一个客户端）并批准验证请求以建立信任。一旦验证，机器人可以解密加密房间中的消息。</p><h2 id="多账户" tabindex="-1">多账户 <a class="header-anchor" href="#多账户" aria-label="Permalink to &quot;多账户&quot;">​</a></h2><p>多账户支持：使用 <code>channels.matrix.accounts</code> 和每账户凭据及可选 <code>name</code>。参见 <a href="/gateway/configuration.html#telegramaccounts--discordaccounts--slackaccounts--signalaccounts--imessageaccounts"><code>gateway/configuration</code></a> 了解共享模式。</p><p>每个账户作为独立的 Matrix 用户在任何 homeserver 上运行。每账户配置继承自顶层 <code>channels.matrix</code> 设置并可以覆盖任何选项（私信策略、群组、加密等）。</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    matrix</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      dm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">policy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pairing&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      accounts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        assistant</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Main assistant&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          homeserver</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://matrix.example.org&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          accessToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;syt_assistant_***&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          encryption</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        },</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        alerts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Alerts bot&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          homeserver</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://matrix.example.org&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          accessToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;syt_alerts_***&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          dm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">policy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allowlist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">allowFrom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@admin:example.org&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>注意：</p><ul><li>账户启动是串行化的，以避免并发模块导入的竞争条件。</li><li>环境变量（<code>MATRIX_HOMESERVER</code>、<code>MATRIX_ACCESS_TOKEN</code> 等）仅适用于 <strong>默认</strong>账户。</li><li>基础渠道设置（私信策略、群组策略、提及门控等）适用于所有账户，除非按账户覆盖。</li><li>使用 <code>bindings[].match.accountId</code> 将每个账户路由到不同的代理。</li><li>加密状态按账户 + 访问令牌存储（每个账户有独立的密钥存储）。</li></ul><h2 id="路由模型" tabindex="-1">路由模型 <a class="header-anchor" href="#路由模型" aria-label="Permalink to &quot;路由模型&quot;">​</a></h2><ul><li>回复始终返回 Matrix。</li><li>私信共享代理的主会话；房间映射到群组会话。</li></ul><h2 id="访问控制-私信" tabindex="-1">访问控制（私信） <a class="header-anchor" href="#访问控制-私信" aria-label="Permalink to &quot;访问控制（私信）&quot;">​</a></h2><ul><li>默认：<code>channels.matrix.dm.policy = &quot;pairing&quot;</code>。未知发送者收到配对代码。</li><li>批准方式： <ul><li><code>openclaw pairing list matrix</code></li><li><code>openclaw pairing approve matrix &lt;CODE&gt;</code></li></ul></li><li>公开私信：<code>channels.matrix.dm.policy=&quot;open&quot;</code> 加上 <code>channels.matrix.dm.allowFrom=[&quot;*&quot;]</code>。</li><li><code>channels.matrix.dm.allowFrom</code> 接受完整的 Matrix 用户 ID（例如 <code>@user:server</code>）。向导在目录搜索找到单个精确匹配时将显示名称解析为用户 ID。</li><li>不要使用显示名称或裸本地部分（例如 <code>&quot;Alice&quot;</code> 或 <code>&quot;alice&quot;</code>）。它们是模糊的，会被白名单匹配忽略。使用完整的 <code>@user:server</code> ID。</li></ul><h2 id="房间-群组" tabindex="-1">房间（群组） <a class="header-anchor" href="#房间-群组" aria-label="Permalink to &quot;房间（群组）&quot;">​</a></h2><ul><li>默认：<code>channels.matrix.groupPolicy = &quot;allowlist&quot;</code>（提及门控）。使用 <code>channels.defaults.groupPolicy</code> 覆盖未设置时的默认。</li><li>运行时注意：如果完全缺少 <code>channels.matrix</code>，运行时回退到 <code>groupPolicy=&quot;allowlist&quot;</code> 进行房间检查（即使设置了 <code>channels.defaults.groupPolicy</code>）。</li><li>使用 <code>channels.matrix.groups</code> 白名单房间（房间 ID 或别名；名称在目录搜索找到单个精确匹配时解析为 ID）：</li></ul><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    matrix</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      groupPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allowlist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      groups</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;!roomId:example.org&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">allow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;#alias:example.org&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">allow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      groupAllowFrom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@owner:example.org&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li><code>requireMention: false</code> 启用该房间的自动回复。</li><li><code>groups.&quot;*&quot;</code> 可以为跨房间的提及门控设置默认值。</li><li><code>groupAllowFrom</code> 限制哪些发送者可以在房间中触发机器人（完整的 Matrix 用户 ID）。</li><li>按房间 <code>users</code> 白名单可以进一步限制特定房间内的发送者（使用完整的 Matrix 用户 ID）。</li><li>配置向导提示输入房间白名单（房间 ID、别名或名称）并且仅在精确、唯一匹配时解析名称。</li><li>启动时，OpenClaw 解析白名单中的房间/用户名称为 ID 并记录映射；未解析的条目在白名单匹配中被忽略。</li><li>邀请默认自动加入；使用 <code>channels.matrix.autoJoin</code> 和 <code>channels.matrix.autoJoinAllowlist</code> 控制。</li><li>要<strong>不允许任何房间</strong>，设置 <code>channels.matrix.groupPolicy: &quot;disabled&quot;</code>（或保持空白名单）。</li><li>传统键：<code>channels.matrix.rooms</code>（与 <code>groups</code> 相同的形状）。</li></ul><h2 id="线程" tabindex="-1">线程 <a class="header-anchor" href="#线程" aria-label="Permalink to &quot;线程&quot;">​</a></h2><ul><li>支持回复线程。</li><li><code>channels.matrix.threadReplies</code> 控制回复是否保持在线程中： <ul><li><code>off</code>、<code>inbound</code>（默认）、<code>always</code></li></ul></li><li><code>channels.matrix.replyToMode</code> 控制不在线程中回复时的回复元数据： <ul><li><code>off</code>（默认）、<code>first</code>、<code>all</code></li></ul></li></ul><h2 id="功能" tabindex="-1">功能 <a class="header-anchor" href="#功能" aria-label="Permalink to &quot;功能&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>状态</th></tr></thead><tbody><tr><td>私信</td><td>✅ 支持</td></tr><tr><td>房间</td><td>✅ 支持</td></tr><tr><td>线程</td><td>✅ 支持</td></tr><tr><td>媒体</td><td>✅ 支持</td></tr><tr><td>E2EE</td><td>✅ 支持（需要加密模块）</td></tr><tr><td>反应</td><td>✅ 支持（通过工具发送/读取）</td></tr><tr><td>投票</td><td>✅ 支持发送；入站投票开始转换为文本（响应/结束忽略）</td></tr><tr><td>位置</td><td>✅ 支持（geo URI；忽略高度）</td></tr><tr><td>原生命令</td><td>✅ 支持</td></tr></tbody></table><h2 id="故障排除" tabindex="-1">故障排除 <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;故障排除&quot;">​</a></h2><p>首先运行这个：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --follow</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --probe</span></span></code></pre></div><p>然后如需要确认私信配对状态：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> matrix</span></span></code></pre></div><p>常见失败：</p><ul><li>已登录但房间消息被忽略：房间被 <code>groupPolicy</code> 或房间白名单阻止。</li><li>私信被忽略：当 <code>channels.matrix.dm.policy=&quot;pairing&quot;</code> 时发送者待批准。</li><li>加密房间失败：加密支持或加密设置不匹配。</li></ul><p>分类流程：<a href="/channels/troubleshooting.html">/channels/troubleshooting</a></p><h2 id="配置参考-matrix" tabindex="-1">配置参考（Matrix） <a class="header-anchor" href="#配置参考-matrix" aria-label="Permalink to &quot;配置参考（Matrix）&quot;">​</a></h2><p>完整配置：<a href="/gateway/configuration.html">配置</a></p><p>提供商选项：</p><ul><li><code>channels.matrix.enabled</code>：启用/禁用渠道启动。</li><li><code>channels.matrix.homeserver</code>：homeserver URL。</li><li><code>channels.matrix.userId</code>：Matrix 用户 ID（使用访问令牌时可选）。</li><li><code>channels.matrix.accessToken</code>：访问令牌。</li><li><code>channels.matrix.password</code>：用于登录的密码（令牌存储）。</li><li><code>channels.matrix.deviceName</code>：设备显示名称。</li><li><code>channels.matrix.encryption</code>：启用 E2EE（默认：false）。</li><li><code>channels.matrix.initialSyncLimit</code>：初始同步限制。</li><li><code>channels.matrix.threadReplies</code>：<code>off | inbound | always</code>（默认：inbound）。</li><li><code>channels.matrix.textChunkLimit</code>：出站文本块大小（字符）。</li><li><code>channels.matrix.chunkMode</code>：<code>length</code>（默认）或 <code>newline</code> 在长度分块之前按空行（段落边界）拆分。</li><li><code>channels.matrix.dm.policy</code>：<code>pairing | allowlist | open | disabled</code>（默认：pairing）。</li><li><code>channels.matrix.dm.allowFrom</code>：私信白名单（完整 Matrix 用户 ID）。<code>open</code> 需要 <code>&quot;*&quot;</code>。向导在可能时将名称解析为 ID。</li><li><code>channels.matrix.groupPolicy</code>：<code>allowlist | open | disabled</code>（默认：allowlist）。</li><li><code>channels.matrix.groupAllowFrom</code>：群组消息的白名单发送者（完整 Matrix 用户 ID）。</li><li><code>channels.matrix.allowlistOnly</code>：强制白名单规则用于私信 + 房间。</li><li><code>channels.matrix.groups</code>：群组白名单 + 按房间设置映射。</li><li><code>channels.matrix.rooms</code>：传统群组白名单/配置。</li><li><code>channels.matrix.replyToMode</code>：线程/标签的回复模式。</li><li><code>channels.matrix.mediaMaxMb</code>：入站/出站媒体上限（MB）。</li><li><code>channels.matrix.autoJoin</code>：邀请处理（<code>always | allowlist | off</code>，默认：always）。</li><li><code>channels.matrix.autoJoinAllowlist</code>：自动加入的允许房间 ID/别名。</li><li><code>channels.matrix.accounts</code>：多账户配置，按账户 ID 键控（每个账户继承顶层设置）。</li><li><code>channels.matrix.actions</code>：按操作工具门控（reactions/messages/pins/memberInfo/channelInfo）。</li></ul>',54)])])}]]);export{n as __pageData,t as default};
